diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..bd6aa7a16781 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3202,6 +3202,19 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
       match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
     return replaceOperand(SI, 0, A);
+  // select (select C, icmp1, false), icmp2, false -> select C, combined_icmp, false
+  // when icmp1 and icmp2 form a range check that can be simplified.
+  // E.g., (x > -1) && (x < n) -> x <u n (for n >= 0)
+  // Only handle scalar types for now.
+  if (CondVal->getType()->isIntegerTy(1) &&
+      match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
+      match(FalseVal, m_Zero())) {
+    if (auto *ICmp1 = dyn_cast<ICmpInst>(B))
+      if (auto *ICmp2 = dyn_cast<ICmpInst>(TrueVal))
+        if (Value *V = simplifyRangeCheck(ICmp1, ICmp2, /*Inverted=*/false))
+          return SelectInst::Create(A, V, Zero);
+  }
+

   // ~(A & B) & (A | B) --> A ^ B
   if (match(&SI, m_c_LogicalAnd(m_Not(m_LogicalAnd(m_Value(A), m_Value(B))),

